          </div>
          {[['Comissão ML',`- R$${com.toFixed(2)}`,C.red],['Frete',`- R$${frete.toFixed(2)}`,C.red],['Impostos',`- R$${imp.toFixed(2)}`,C.red],['Lucro líquido',`R$${lucro.toFixed(2)}`,lucro>0?C.green:C.red]].map(([l,v,c]) => (
